(()=>{if(window.webstatsRequestSent)return;window.webstatsRequestSent=!0;const e=document.currentScript,t=e&&e.getAttribute("data-api")||window.WEBSTATS_API||"";let n="";try{n=t||new URL(e&&e.src?e.src:location.href).origin}catch{n=location.origin}const o=n.replace(/\/$/,"")+"/api.php";fetch(o,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({url:location.href,referrer:document.referrer})}).then(e=>e.json()).then(e=>{for(const t in e)document.querySelectorAll("#"+t).forEach(t=>t.innerText=e[t])}).catch(e=>console.error(e))})();
